CREATE TABLE "languages" (
                             "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
                             "code" varchar(5) UNIQUE NOT NULL,
                             "name" varchar(100) NOT NULL,
                             "native_name" varchar(100),
                             "flag" varchar(10),
                             "is_active" boolean DEFAULT true,
                             "created_at" timestamp DEFAULT (now())
);





CREATE TABLE "languages" (
                             "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
                             "code" varchar(5) UNIQUE NOT NULL,
                             "name" varchar(100) NOT NULL,
                             "native_name" varchar(100),
                             "flag" varchar(10),
                             "is_active" boolean DEFAULT true,
                             "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "page_texto" (
                              "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
                              "texto" varchar(1000) UNIQUE NOT NULL,
                              "date_created" timestamp
);

CREATE TABLE "page_texto_translated" (
                                         "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY NOT NULL,
                                         "id_page_texto" int NOT NULL,
                                         "id_language" int NOT NULL,
                                         "texto_translated" varchar(1000) NOT NULL
);


CREATE INDEX ON "page_texto_translated" ("id_page_texto");

CREATE INDEX ON "page_texto_translated" ("id_language");

COMMENT ON COLUMN "languages"."code" IS 'Código ISO 639-1 (ej. en, es)';

COMMENT ON COLUMN "languages"."name" IS 'Nombre del idioma';

COMMENT ON COLUMN "languages"."native_name" IS 'Nombre en su idioma original';

COMMENT ON COLUMN "languages"."flag" IS 'Emoji de la bandera del país representativo';

ALTER TABLE "page_texto_translated" ADD CONSTRAINT "page_text_translated_text" FOREIGN KEY ("id_page_texto") REFERENCES "page_texto" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "page_texto_translated" ADD CONSTRAINT "page_text_translated_language" FOREIGN KEY ("id_language") REFERENCES "languages" ("id") DEFERRABLE INITIALLY IMMEDIATE;
